CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;


DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260706173205_Intial_script') THEN
    CREATE TABLE "Users" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "CognitoSub" character varying(128) NOT NULL,
        "Email" character varying(256) NOT NULL,
        "Name" character varying(256) NOT NULL,
        "PictureUrl" character varying(1024),
        "IsActive" boolean NOT NULL DEFAULT TRUE,
        "UploadLimit" integer NOT NULL DEFAULT 5,
        "UploadsUsed" integer NOT NULL DEFAULT 0,
        "QuotaResetAt" timestamp with time zone,
        "IsAdmin" boolean NOT NULL DEFAULT FALSE,
        "AdminNotes" character varying(500),
        "CreatedAt" timestamp with time zone NOT NULL,
        "LastLoginAt" timestamp with time zone,
        CONSTRAINT "PK_Users" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260706173205_Intial_script') THEN
    CREATE TABLE "IntegrationSettings" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "UserId" integer NOT NULL,
        "Provider" character varying(50) NOT NULL,
        "SettingsJson" jsonb NOT NULL,
        "IsActive" boolean NOT NULL,
        "CreatedAt" timestamp with time zone NOT NULL,
        "UpdatedAt" timestamp with time zone,
        CONSTRAINT "PK_IntegrationSettings" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_IntegrationSettings_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE CASCADE
    );
    END IF;
END $EF$;

DO $EF$
