    CREATE TABLE "Projects" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "UserId" integer NOT NULL,
        "Name" character varying(100) NOT NULL,
        "LinkedProvider" text,
        "CreatedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_Projects" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_Projects_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE CASCADE
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260706173205_Intial_script') THEN
    CREATE TABLE "Meetings" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "UserId" integer NOT NULL,
        "Name" character varying(50) NOT NULL,
        "Description" character varying(100),
        "ProjectId" integer,
        "TemplateId" character varying(50) NOT NULL,
        "AudioFileName" character varying(255) NOT NULL,
        "AudioFileSize" bigint NOT NULL,
        "AudioStoragePath" text,
        "Status" character varying(20) NOT NULL,
        "ErrorMessage" character varying(500),
        "Transcript" text,
        "ExtractionResultJson" text NOT NULL,
        "EditedResultJson" text,
        "MeetingDate" timestamp with time zone,
        "CreatedAt" timestamp with time zone NOT NULL,
        "CompletedAt" timestamp with time zone,
        CONSTRAINT "PK_Meetings" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_Meetings_Projects_ProjectId" FOREIGN KEY ("ProjectId") REFERENCES "Projects" ("Id") ON DELETE SET NULL,
        CONSTRAINT "FK_Meetings_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE CASCADE
    );
    END IF;
END $EF$;

